blocks.code:
let lambda = ts.sample_ext();
intermediate_tidx[0] = ts.len();

for coef in univariate_round_coeffs {
    ts.observe_ext(*coef);
}
let u0 = ts.sample_ext();
let univariate_poly_rand_eval = izip!(univariate_round_coeffs, u0.powers())
    .map(|(&coef, pow)| coef * pow)
    .sum();
sumcheck_rnd.push(u0);
intermediate_tidx[1] = ts.len();

for poly in sumcheck_round_polys {
    for eval in poly {
        ts.observe_ext(*eval);
    }
    let ui = ts.sample_ext();
    sumcheck_rnd.push(ui);
}
intermediate_tidx[2] = ts.len();

for matrix_openings in stacking_openings {
    for col_opening in matrix_openings {
        ts.observe_ext(*col_opening);
    }
}

// μ PoW: observe witness and sample before sampling μ
let mu_pow_witness = proof.whir_proof.mu_pow_witness;
let mu_pow_sample = pow_observe_sample(ts, self.mu_pow_bits, mu_pow_witness);

let stacking_batching_challenge = ts.sample_ext();

/*
 * Constrain the sortedness of each ColumnClaimsMessage. Main claims (i.e part_idx = 0)
 * should be first and sorted by sort_idx and then col_idx. The remaining claims should
 * be sorted by sort_idx, then part_idx, and finally col_idx. Note that each proof must
 * have at least one main claim.
 */
builder.assert_bool(local.is_main);
builder.when(local.is_main).assert_one(local.is_valid);
builder.when(local.is_main).assert_zero(local.part_idx);
builder.when(local.is_main).assert_zero(local.commit_idx);

builder.when(local.is_first).assert_one(local.is_main);
builder.when(local.is_first).assert_zero(local.sort_idx);
builder.when(local.is_first).assert_zero(local.col_idx);

builder.assert_bool(local.is_transition_main);
builder
    .when(local.is_transition_main)
    .assert_eq(local.is_main, next.is_main);
builder
    .when(local.is_transition_main)
    .assert_one(and(local.is_valid, next.is_valid));
builder
    .when(and::<AB::Expr>(
        and(local.is_main, next.is_main),
        not(local.is_last),
    ))
    .assert_one(local.is_transition_main);
builder
    .when(and(
        and::<AB::Expr>(not(local.is_main), not(next.is_main)),
        next.is_valid,
    ))
    .assert_one(local.is_transition_main);
builder
    .when(local.is_transition_main)
    .assert_zero(local.is_last);
builder
    .when(and(not(local.is_main), next.is_main))
    .assert_one(local.is_last);

let mut when_both_main = builder.when(and(local.is_main, local.is_transition_main));
when_both_main.assert_bool(next.sort_idx - local.sort_idx);
when_both_main
    .when_ne(local.sort_idx, next.sort_idx)
    .assert_zero(next.col_idx);
when_both_main
    .when_ne(local.sort_idx + AB::F::ONE, next.sort_idx)
    .assert_one(next.col_idx - local.col_idx);

let mut when_last_main = builder.when(and(local.is_main, not(local.is_transition_main)));
when_last_main.assert_zero((next.part_idx - AB::F::ONE) * not(local.is_last));
when_last_main.assert_zero(next.col_idx * not(local.is_last));

self.column_claims_bus.send(
    builder,
    local.proof_idx,
    ColumnClaimsMessage {
        sort_idx: local.sort_idx.into(),
        part_idx: local.part_idx.into(),
        col_idx: local.col_idx.into(),
        claim: local.col_claim.map(Into::into),
        is_rot: AB::Expr::ZERO,
    },
    local.is_valid,
);

for i in 0..D_EF {
    builder
        .when(and(local.is_valid, not(local.need_rot)))
        .assert_zero(local.rot_claim[i]);
}
self.column_claims_bus.send(
    builder,
    local.proof_idx,
    ColumnClaimsMessage {
        sort_idx: local.sort_idx.into(),
        part_idx: local.part_idx.into(),
        col_idx: local.col_idx.into(),
        claim: local.rot_claim.map(Into::into),
        is_rot: AB::Expr::ONE,
    },
    local.is_valid * local.need_rot,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_multiply(
        ext_field_multiply(local.lambda, local.lambda),
        local.lambda_pow,
    ),
    next.lambda_pow,
);

assert_one_ext(&mut builder.when(local.is_first), local.lambda_pow);

assert_array_eq(
    &mut builder.when(local.is_first),
    ext_field_add::<AB::Expr>(
        local.col_claim,
        ext_field_multiply(local.lambda, local.rot_claim),
    ),
    local.s_0,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_add(
        local.s_0,
        ext_field_add::<AB::Expr>(
            ext_field_multiply(next.lambda_pow, next.col_claim),
            ext_field_multiply(
                ext_field_multiply(next.lambda_pow, next.lambda),
                next.rot_claim,
            ),
        ),
    ),
    next.s_0,
);

self.sumcheck_claims_bus.send(
    builder,
    local.proof_idx,
    SumcheckClaimsMessage {
        module_idx: AB::Expr::ZERO,
        value: local.s_0.map(Into::into),
    },
    and(local.is_last, local.is_valid),
);

assert_array_eq(
    builder,
    ext_field_multiply(local.lambda_pow, local.eq_bits),
    local.lambda_pow_eq_bits,
);

assert_array_eq(
    builder,
    local.k_rot_in_when_needed,
    ext_field_multiply_scalar(local.k_rot_in, local.need_rot),
);

assert_array_eq(
    &mut builder.when(local.is_first),
    ext_field_multiply(
        local.lambda_pow_eq_bits,
        ext_field_add::<AB::Expr>(
            local.eq_in,
            ext_field_multiply(local.lambda, local.k_rot_in_when_needed),
        ),
    ),
    local.stacking_claim_coefficient,
);

assert_array_eq(
    &mut builder.when(local.is_last_for_claim),
    ext_field_multiply(
        next.lambda_pow_eq_bits,
        ext_field_add::<AB::Expr>(
            next.eq_in,
            ext_field_multiply(next.lambda, next.k_rot_in_when_needed),
        ),
    ),
    next.stacking_claim_coefficient,
);

assert_array_eq(
    &mut builder.when(not::<AB::Expr>(local.is_last_for_claim)),
    ext_field_add(
        local.stacking_claim_coefficient,
        ext_field_multiply(
            next.lambda_pow_eq_bits,
            ext_field_add::<AB::Expr>(
                next.eq_in,
                ext_field_multiply(next.lambda, next.k_rot_in_when_needed),
            ),
        ),
    ),
    next.stacking_claim_coefficient,
);

self.claim_coefficients_bus.send(
    builder,
    local.proof_idx,
    ClaimCoefficientsMessage {
        commit_idx: local.commit_idx,
        stacked_col_idx: local.stacked_col_idx,
        coefficient: local.stacking_claim_coefficient,
    },
    and(local.is_valid, local.is_last_for_claim),
);

self.lifted_heights_bus.lookup_key(
    builder,
    local.proof_idx,
    LiftedHeightsBusMessage {
        sort_idx: local.sort_idx,
        part_idx: local.part_idx,
        commit_idx: local.commit_idx,
        hypercube_dim: local.hypercube_dim,
        lifted_height: local.lifted_height,
        log_lifted_height: local.log_lifted_height,
    },
    local.is_valid,
);

self.eq_kernel_lookup_bus.lookup_key(
    builder,
    local.proof_idx,
    EqKernelLookupMessage {
        n: local.hypercube_dim,
        eq_in: local.eq_in,
        k_rot_in: local.k_rot_in,
    },
    local.is_valid,
);

builder
    .when(local.is_valid)
    .assert_one(local.lifted_height * local.lifted_height_inv);

self.eq_bits_lookup_bus.lookup_key(
    builder,
    local.proof_idx,
    EqBitsLookupMessage {
        b_value: local.row_idx
            * local.lifted_height_inv
            * AB::F::from_usize(1 << self.l_skip),
        num_bits: AB::Expr::from_usize(self.n_stack + self.l_skip)
            - local.log_lifted_height,
        eval: local.eq_bits.map(Into::into),
    },
    local.is_valid,
);

self.stacking_module_bus.receive(
    builder,
    local.proof_idx,
    StackingModuleMessage {
        tidx: local.tidx.into(),
    },
    and(local.is_first, local.is_valid),
);

builder
    .when(and(local.is_valid, not(local.is_last)))
    .assert_eq(local.tidx + AB::Expr::from_usize(2 * D_EF), next.tidx);

for i in 0..D_EF {
    self.transcript_bus.receive(
        builder,
        local.proof_idx,
        TranscriptBusMessage {
            tidx: local.tidx + AB::Expr::from_usize(i),
            value: local.col_claim[i].into(),
            is_sample: AB::Expr::ZERO,
        },
        local.is_valid,
    );

    self.transcript_bus.receive(
        builder,
        local.proof_idx,
        TranscriptBusMessage {
            tidx: local.tidx + AB::Expr::from_usize(D_EF + i),
            value: local.rot_claim[i].into(),
            is_sample: AB::Expr::ZERO,
        },
        local.is_valid,
    );

    self.transcript_bus.receive(
        builder,
        local.proof_idx,
        TranscriptBusMessage {
            tidx: AB::Expr::from_usize(2 * D_EF + i) + local.tidx,
            value: local.lambda[i].into(),
            is_sample: AB::Expr::ONE,
        },
        and(local.is_last, local.is_valid),
    );
}

self.stacking_tidx_bus.send(
    builder,
    local.proof_idx,
    StackingModuleTidxMessage {
        module_idx: AB::Expr::ZERO,
        tidx: local.tidx + AB::Expr::from_usize(3 * D_EF),
    },
    and(local.is_last, local.is_valid),
);

#[repr(C)]
#[derive(AlignedBorrow)]
pub struct UnivariateRoundCols<F> {
    // Proof index columns for continuations
    pub proof_idx: F,
    pub is_valid: F,
    pub is_first: F,
    pub is_last: F,

    // Sampled transcript values
    pub tidx: F,
    pub u_0: [F; D_EF],
    pub u_0_pow: [F; D_EF],

    // Coefficients of univariate round (s_0) polynomial
    pub coeff: [F; D_EF],

    // Columns to compute s_0(z) sum over all z in D
    pub coeff_idx: F,
    pub coeff_is_d: F,
    pub s_0_sum_over_d: [F; D_EF],

    // Evaluation of s_0 polynomial at u_0
    pub poly_rand_eval: [F; D_EF],
}

/*
 * Constrain that the sum of s_0(z) for z in D via interaction equals the RLC of column
 * claims from OpeningClaimsAir. We use the properties of D to do this efficiently -
 * since D is a multiplicative subgroup, it turns out this sum is |D| * (a_0 + a_{|D|}).
 */
let d_card = 1usize << self.l_skip;

builder.when(local.is_first).assert_zero(local.coeff_idx);
builder
    .when(and(local.is_last, local.is_valid))
    .assert_eq(local.coeff_idx, AB::F::from_usize(2 * (d_card - 1)));
builder
    .when(and(not(local.is_last), local.is_valid))
    .assert_one(next.coeff_idx - local.coeff_idx);

builder.assert_bool(local.coeff_is_d);
builder.when(local.coeff_is_d).assert_one(local.is_valid);
builder
    .when(local.coeff_is_d)
    .assert_eq(local.coeff_idx, AB::F::from_usize(d_card));

assert_array_eq(
    &mut builder.when(local.is_first),
    ext_field_multiply_scalar(local.coeff, AB::F::from_usize(d_card)),
    local.s_0_sum_over_d,
);

assert_array_eq(
    &mut builder.when(next.coeff_is_d),
    ext_field_add(
        local.s_0_sum_over_d,
        ext_field_multiply_scalar(next.coeff, AB::F::from_usize(d_card)),
    ),
    next.s_0_sum_over_d,
);

assert_array_eq(
    &mut builder.when(and::<AB::Expr>(not(next.coeff_is_d), not(local.is_last))),
    local.s_0_sum_over_d,
    next.s_0_sum_over_d,
);

self.sumcheck_claims_bus.receive(
    builder,
    next.proof_idx,
    SumcheckClaimsMessage {
        module_idx: AB::Expr::ZERO,
        value: next.s_0_sum_over_d.map(Into::into),
    },
    next.coeff_is_d,
);

/*
 * Compute evaluation of polynomial s_0(u_0) and send it to SumcheckRoundsAir, where
 * it'll be used to constrain the correctness of s_1(0).
 */
assert_one_ext(&mut builder.when(local.is_first), local.u_0_pow);
assert_array_eq(&mut builder.when(not(local.is_last)), local.u_0, next.u_0);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_multiply(local.u_0, local.u_0_pow),
    next.u_0_pow,
);

assert_array_eq(
    &mut builder.when(local.is_first),
    ext_field_multiply(local.coeff, local.u_0_pow),
    local.poly_rand_eval,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_add(
        local.poly_rand_eval,
        ext_field_multiply(next.coeff, next.u_0_pow),
    ),
    next.poly_rand_eval,
);

self.sumcheck_claims_bus.send(
    builder,
    local.proof_idx,
    SumcheckClaimsMessage {
        module_idx: AB::Expr::ONE,
        value: local.poly_rand_eval.map(Into::into),
    },
    and(local.is_last, local.is_valid),
);

/*
 * Because we sample u_0 from the transcript here, we send u_0 to other AIRs that
 * need to use it.
 */
self.eq_rand_values_bus.add_key_with_lookups(
    builder,
    local.proof_idx,
    EqRandValuesLookupMessage {
        idx: AB::Expr::ZERO,
        u: local.u_0.map(Into::into),
    },
    and(local.is_last, local.is_valid) * AB::F::TWO,
);

/*
 * Constrain transcript operations and send the final tidx to SumcheckRoundsAir.
 */
let mut when_same_proof = builder.when(and(local.is_valid, not(local.is_last)));
when_same_proof.assert_one(next.is_valid);
when_same_proof.assert_eq(local.tidx + AB::Expr::from_usize(D_EF), next.tidx);

self.stacking_tidx_bus.receive(
    builder,
    local.proof_idx,
    StackingModuleTidxMessage {
        module_idx: AB::Expr::ZERO,
        tidx: local.tidx.into(),
    },
    local.is_first,
);

for i in 0..D_EF {
    self.transcript_bus.receive(
        builder,
        local.proof_idx,
        TranscriptBusMessage {
            tidx: AB::Expr::from_usize(i) + local.tidx,
            value: local.coeff[i].into(),
            is_sample: AB::Expr::ZERO,
        },
        local.is_valid,
    );

    self.transcript_bus.receive(
        builder,
        local.proof_idx,
        TranscriptBusMessage {
            tidx: AB::Expr::from_usize(i + D_EF) + local.tidx,
            value: local.u_0[i].into(),
            is_sample: AB::Expr::ONE,
        },
        and(local.is_last, local.is_valid),
    );
}

self.stacking_tidx_bus.send(
    builder,
    local.proof_idx,
    StackingModuleTidxMessage {
        module_idx: AB::Expr::ONE,
        tidx: AB::Expr::from_usize(2 * D_EF) + local.tidx,
    },
    and(local.is_last, local.is_valid),
);

#[repr(C)]
#[derive(AlignedBorrow)]
pub struct SumcheckRoundsCols<F> {
    // Proof index columns for continuations
    pub proof_idx: F,
    pub is_valid: F,
    pub is_first: F,
    pub is_last: F,

    // Sumcheck round this row represents
    pub round: F,

    // Starting tidx for this sumcheck round
    pub tidx: F,

    // Evaluations of polynomial s_round
    pub s_eval_at_0: [F; D_EF],
    pub s_eval_at_1: [F; D_EF],
    pub s_eval_at_2: [F; D_EF],
    pub s_eval_at_u: [F; D_EF],

    // Values of sampled u and r for this round
    pub u_round: [F; D_EF],
    pub r_round: [F; D_EF],
    pub has_r: F,
    pub u_mult: F,

    // Values of eq(u_0, r_0), eq(u_0, r_0 * omega), and eq(u_0, 1) * eq(r_0 * omega, 1)
    pub eq_prism_base: [F; D_EF],
    pub eq_cube_base: [F; D_EF],
    pub rot_cube_base: [F; D_EF],

    // Value of eq_cube
    pub eq_cube: [F; D_EF],

    // Intermediate values to compute rot_cube recursively
    pub r_not_u_prod: [F; D_EF],
    pub rot_cube_minus_prod: [F; D_EF],

    // Multiplicity of eq_round(u, r) lookup
    pub eq_rot_mult: F,
}

/*
 * Constrain that s_round(u_round) is the quadratic interpolation using values
 * s_round(0), s_round(1), and s_round(2). Additionally, constrain that we have
 * s_round(u_round) = s_{round + 1}(0) + s_{round + 1}(1), and send the value of
 * s_{n_stack}(u_{n_stack}) to StackingClaimsAir.
 */
self.sumcheck_claims_bus.receive(
    builder,
    local.proof_idx,
    SumcheckClaimsMessage {
        module_idx: AB::Expr::ONE,
        value: ext_field_add(local.s_eval_at_0, local.s_eval_at_1),
    },
    local.is_first,
);

let s1 = ext_field_subtract(local.s_eval_at_1, local.s_eval_at_0);
let s2 = ext_field_subtract(local.s_eval_at_2, local.s_eval_at_1);
let p = ext_field_multiply_scalar::<AB::Expr>(
    ext_field_subtract::<AB::Expr>(s2, s1.clone()),
    AB::F::TWO.inverse(),
);
let q = ext_field_subtract::<AB::Expr>(s1, p.clone());

assert_array_eq(
    builder,
    ext_field_add(
        ext_field_multiply(
            ext_field_add::<AB::Expr>(ext_field_multiply(p, local.u_round), q),
            local.u_round,
        ),
        local.s_eval_at_0,
    ),
    local.s_eval_at_u,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    local.s_eval_at_u,
    ext_field_add(next.s_eval_at_0, next.s_eval_at_1),
);

self.sumcheck_claims_bus.send(
    builder,
    local.proof_idx,
    SumcheckClaimsMessage {
        module_idx: AB::Expr::TWO,
        value: local.s_eval_at_u.map(Into::into),
    },
    and(local.is_last, local.is_valid),
);

self.eq_base_bus.receive(
    builder,
    local.proof_idx,
    EqBaseMessage {
        eq_u_r: local.eq_prism_base,
        eq_u_r_omega: local.eq_cube_base,
        eq_u_r_prod: local.rot_cube_base,
    },
    local.is_first,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    local.eq_prism_base,
    next.eq_prism_base,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    local.eq_cube_base,
    next.eq_cube_base,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    local.rot_cube_base,
    next.rot_cube_base,
);

let local_u_not_r = ext_field_multiply(local.u_round, ext_field_one_minus(local.r_round));
let local_r_not_u = ext_field_multiply(local.r_round, ext_field_one_minus(local.u_round));
let next_u_not_r = ext_field_multiply(next.u_round, ext_field_one_minus(next.r_round));
let next_r_not_u = ext_field_multiply(next.r_round, ext_field_one_minus(next.u_round));

assert_array_eq(
    &mut builder.when(local.is_first),
    ext_field_one_minus::<AB::Expr>(ext_field_add::<AB::Expr>(
        local_u_not_r.clone(),
        local_r_not_u.clone(),
    )),
    local.eq_cube,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_multiply(
        local.eq_cube,
        ext_field_one_minus::<AB::Expr>(ext_field_add::<AB::Expr>(
            next_u_not_r.clone(),
            next_r_not_u.clone(),
        )),
    ),
    next.eq_cube,
);

assert_array_eq(
    &mut builder.when(local.is_first),
    local.r_not_u_prod,
    local_r_not_u,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_multiply(local.r_not_u_prod, next_r_not_u.clone()),
    next.r_not_u_prod,
);

assert_array_eq(
    &mut builder.when(local.is_first),
    local.rot_cube_minus_prod,
    local_u_not_r,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_add::<AB::Expr>(
        ext_field_multiply(
            local.rot_cube_minus_prod,
            ext_field_one_minus::<AB::Expr>(ext_field_add::<AB::Expr>(
                next_u_not_r.clone(),
                next_r_not_u,
            )),
        ),
        ext_field_multiply(next_u_not_r, local.r_not_u_prod),
    ),
    next.rot_cube_minus_prod,
);

self.eq_kernel_lookup_bus.add_key_with_lookups(
    builder,
    local.proof_idx,
    EqKernelLookupMessage {
        n: local.round.into(),
        eq_in: ext_field_multiply(local.eq_prism_base, local.eq_cube),
        k_rot_in: ext_field_add(
            ext_field_multiply(local.eq_cube_base, local.eq_cube),
            ext_field_multiply(
                local.rot_cube_base,
                ext_field_subtract(
                    ext_field_add(local.r_not_u_prod, local.rot_cube_minus_prod),
                    local.eq_cube,
                ),
            ),
        ),
    },
    local.is_valid * local.eq_rot_mult,
);

builder.assert_bool(local.has_r);
builder
    .when(and(local.is_valid, not(local.is_last)))
    .assert_bool(local.has_r - next.has_r);
builder
    .when(not(local.has_r))
    .assert_zero(local.eq_rot_mult);

assert_zeros(&mut builder.when(not(local.has_r)), local.r_round);

self.constraint_randomness_bus.receive(
    builder,
    local.proof_idx,
    ConstraintSumcheckRandomness {
        idx: local.round,
        challenge: local.r_round,
    },
    and(local.is_valid, local.has_r),
);

self.whir_opening_point_bus.send(
    builder,
    local.proof_idx,
    WhirOpeningPointMessage {
        idx: local.round + AB::Expr::from_usize(self.l_skip - 1),
        value: local.u_round.map(Into::into),
    },
    local.is_valid,
);

self.eq_rand_values_bus.add_key_with_lookups(
    builder,
    local.proof_idx,
    EqRandValuesLookupMessage {
        idx: local.round,
        u: local.u_round,
    },
    local.u_mult,
);
builder.when(not(local.is_valid)).assert_zero(local.u_mult);

self.stacking_tidx_bus.receive(
    builder,
    local.proof_idx,
    StackingModuleTidxMessage {
        module_idx: AB::Expr::ONE,
        tidx: local.tidx.into(),
    },
    local.is_first,
);

builder
    .when(not(local.is_last) * local.is_valid)
    .assert_eq(local.tidx + AB::F::from_usize(3 * D_EF), next.tidx);

for i in 0..D_EF {
    self.transcript_bus.receive(
        builder,
        local.proof_idx,
        TranscriptBusMessage {
            tidx: AB::Expr::from_usize(i) + local.tidx,
            value: local.s_eval_at_1[i].into(),
            is_sample: AB::Expr::ZERO,
        },
        local.is_valid,
    );

    self.transcript_bus.receive(
        builder,
        local.proof_idx,
        TranscriptBusMessage {
            tidx: AB::Expr::from_usize(i + D_EF) + local.tidx,
            value: local.s_eval_at_2[i].into(),
            is_sample: AB::Expr::ZERO,
        },
        local.is_valid,
    );

    self.transcript_bus.receive(
        builder,
        local.proof_idx,
        TranscriptBusMessage {
            tidx: AB::Expr::from_usize(i + 2 * D_EF) + local.tidx,
            value: local.u_round[i].into(),
            is_sample: AB::Expr::ONE,
        },
        local.is_valid,
    );
}

self.stacking_tidx_bus.send(
    builder,
    local.proof_idx,
    StackingModuleTidxMessage {
        module_idx: AB::Expr::TWO,
        tidx: AB::Expr::from_usize(3 * D_EF) + local.tidx,
    },
    and(local.is_last, local.is_valid),
);

#[repr(C)]
#[derive(AlignedBorrow)]
pub struct EqBaseCols<F> {
    // Proof index columns for continuations
    pub proof_idx: F,
    pub is_valid: F,
    pub is_first: F,
    pub is_last: F,

    // Row index for the given proof, in {0, 1, ..., l_skip}
    pub row_idx: F,

    // Value of u^{2^row}, r^{2^row}, and (r * omega)^{2^row}
    pub u_pow: [F; D_EF],
    pub r_pow: [F; D_EF],
    pub r_omega_pow: [F; D_EF],

    // Running product of (u^{2^i} + r^{2^i}) from i to row
    pub prod_u_r: [F; D_EF],
    pub prod_u_r_omega: [F; D_EF],
    pub prod_u_1: [F; D_EF],
    pub prod_r_omega_1: [F; D_EF],

    // Lookup multiplicity for eq_0(u, r) and k_rot_0(u, r)
    pub mult: F,

    // Value of u^{2^{l_skip + n}}, where we set n = -row_idx
    pub u_pow_rev: [F; D_EF],

    // Values of eq_n(u, r) and k_rot_n(u, r) for each negative n
    pub eq_neg: [F; D_EF],
    pub k_rot_neg: [F; D_EF],

    // Value of in_n(u) for n in {-1, -2, ..., -l_skip}, i.e. the running product of
    // each (u_pow_rev + 1)
    pub in_prod: [F; D_EF],

    // Lookup multiplicity for eq_n(u, r) and k_rot_n(u, r)
    pub mult_neg: F,
}

/*
 * Constrain value of row_idx and send u^{2^row} to WhirOpeningPointBus when
 * row_idx < l_skip.
 */
let is_valid_transition = and(local.is_valid, not(local.is_last));

builder.when(local.is_first).assert_zero(local.row_idx);
builder
    .when(is_valid_transition.clone())
    .assert_eq(local.row_idx + AB::F::ONE, next.row_idx);
builder
    .when(and(local.is_valid, local.is_last))
    .assert_eq(local.row_idx, AB::F::from_usize(self.l_skip));

self.whir_opening_point_bus.send(
    builder,
    local.proof_idx,
    WhirOpeningPointMessage {
        idx: local.row_idx,
        value: local.u_pow,
    },
    is_valid_transition,
);

/*
 * Receive the values of u_0 and r_0 from the AIRs that sample them. Send u_0
 * and r_0^2 to EqNegAir.
 */
self.constraint_randomness_bus.receive(
    builder,
    local.proof_idx,
    ConstraintSumcheckRandomness {
        idx: AB::Expr::ZERO,
        challenge: local.r_pow.map(Into::into),
    },
    local.is_first,
);

self.eq_rand_values_bus.lookup_key(
    builder,
    local.proof_idx,
    EqRandValuesLookupMessage {
        idx: AB::Expr::ZERO,
        u: ext_field_add(
            ext_field_multiply_scalar(local.u_pow, local.is_first),
            ext_field_multiply_scalar(local.u_pow_rev, local.is_last),
        ),
    },
    and(local.is_valid, local.is_first + local.is_last),
);

self.eq_neg_base_rand_bus.send(
    builder,
    local.proof_idx,
    EqNegBaseRandMessage {
        u: local.u_pow.map(Into::into),
        r_squared: ext_field_multiply(local.r_pow, local.r_pow),
    },
    local.is_first,
);

/*
 * Constrain the running product of (u^{2^i} + r^{2^i}) from i to row, which is
 * used to compute eq_0(u, r).
 */
assert_array_eq(
    &mut builder.when(local.is_first),
    local.prod_u_r,
    ext_field_multiply(local.u_pow, ext_field_add(local.u_pow, local.r_pow)),
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_multiply(local.u_pow, local.u_pow),
    next.u_pow,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_multiply(local.r_pow, local.r_pow),
    next.r_pow,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_multiply(local.prod_u_r, ext_field_add(next.u_pow, next.r_pow)),
    next.prod_u_r,
);

/*
 * Constrain the running product that is used to compute eq_0(u, r * omega).
 */
let omega = AB::F::two_adic_generator(self.l_skip);

assert_array_eq(
    &mut builder.when(local.is_first),
    local.prod_u_r_omega,
    ext_field_multiply(local.u_pow, ext_field_add(local.u_pow, local.r_omega_pow)),
);

assert_array_eq(
    &mut builder.when(local.is_first),
    local.r_omega_pow,
    ext_field_multiply_scalar(local.r_pow, omega),
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_multiply(local.r_omega_pow, local.r_omega_pow),
    next.r_omega_pow,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_multiply(
        local.prod_u_r_omega,
        ext_field_add(next.u_pow, next.r_omega_pow),
    ),
    next.prod_u_r_omega,
);

/*
 * Compute eq_0(u, r) and eq_0(u, r * omega), which are sent to the lookup
 * bus. Note that k_rot_0(u, r) = eq_0(u, r * omega).
 */
let omega_pow_inv = AB::F::from_usize(1 << self.l_skip).inverse();

let eq_u_r = ext_field_multiply_scalar(
    ext_field_add::<AB::Expr>(ext_field_subtract(local.prod_u_r, next.u_pow), ef_one),
    omega_pow_inv,
);

let eq_u_r_omega = ext_field_multiply_scalar(
    ext_field_add::<AB::Expr>(ext_field_subtract(local.prod_u_r_omega, next.u_pow), ef_one),
    omega_pow_inv,
);

builder.when(next.mult).assert_one(next.is_last);

self.eq_kernel_lookup_bus.add_key_with_lookups(
    builder,
    local.proof_idx,
    EqKernelLookupMessage {
        n: AB::Expr::ZERO,
        eq_in: eq_u_r.clone(),
        k_rot_in: eq_u_r_omega.clone(),
    },
    next.is_valid * next.mult,
);

/*
 * Compute eq_0(u, 1) and eq_0(r * omega, 1) and send to SumcheckRoundsAir.
 */
let eq_u_1 = ext_field_multiply_scalar(local.prod_u_1, omega_pow_inv);
let eq_r_omega_1 = ext_field_multiply_scalar(local.prod_r_omega_1, omega_pow_inv);

self.eq_base_bus.send(
    builder,
    local.proof_idx,
    EqBaseMessage {
        eq_u_r,
        eq_u_r_omega,
        eq_u_r_prod: ext_field_multiply(eq_u_1, eq_r_omega_1),
    },
    and(next.is_last, next.is_valid),
);

/*
 * Compute eq_n(u, r), k_rot_n(u, r), and in_n(u), which are used to
 * provide the eq and k_rot lookups for n < 0.
 */
self.eq_neg_result_bus.receive(
    builder,
    local.proof_idx,
    EqNegResultMessage {
        n: AB::Expr::ZERO - local.row_idx,
        eq: local.eq_neg.map(Into::into),
        k_rot: local.k_rot_neg.map(Into::into),
    },
    and(
        local.is_valid,
        not::<AB::Expr>(or(local.is_first, local.is_last)),
    ),
);

assert_one_ext(
    &mut builder.when(and(local.is_valid, local.is_last)),
    local.eq_neg,
);

assert_one_ext(
    &mut builder.when(and(local.is_valid, local.is_last)),
    local.k_rot_neg,
);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_multiply(next.u_pow_rev, next.u_pow_rev),
    local.u_pow_rev,
);

assert_one_ext(&mut builder.when(local.is_first), local.in_prod);

assert_array_eq(
    &mut builder.when(not(local.is_last)),
    ext_field_multiply(
        local.in_prod,
        ext_field_add_scalar(next.u_pow_rev, AB::F::ONE),
    ),
    next.in_prod,
);

builder
    .when(not(local.is_valid))
    .assert_zero(local.mult_neg);
builder.when(local.is_first).assert_zero(local.mult_neg);

let in_n = ext_field_multiply_scalar::<AB::Expr>(local.in_prod, omega_pow_inv);
self.eq_kernel_lookup_bus.add_key_with_lookups(
    builder,
    local.proof_idx,
    EqKernelLookupMessage {
        n: AB::Expr::ZERO - local.row_idx,
        eq_in: ext_field_multiply(in_n.clone(), local.eq_neg),
        k_rot_in: ext_field_multiply(in_n, local.k_rot_neg),
    },
    local.mult_neg,
);

#[repr(C)]
#[derive(AlignedBorrow)]
pub struct EqBitsCols<F> {
    // Proof index columns for continuations
    pub proof_idx: F,
    pub is_valid: F,
    pub is_first: F,

    // Multiplicities of internal and external lookups
    pub internal_child_flag: F,
    pub external_mult: F,

    // Parent row's b_value and evaluation
    pub sub_b_value: F,
    pub sub_eval: [F; D_EF],

    // This row's b_value's LSB, number of bits, and u_{n_stack - num_bits + 1}
    pub b_lsb: F,
    pub num_bits: F,
    pub u_val: [F; D_EF],
}

/*
 * Constrain that the root evaluation is correct, i.e. eq_bits([], []) = 1.
 */
let mut when_first = builder.when(local.is_first);

when_first.assert_zero(local.sub_b_value);
when_first.assert_zero(local.num_bits);
when_first.assert_zero(local.b_lsb);

assert_zeros(&mut when_first, local.u_val);
assert_one_ext(&mut when_first, local.sub_eval);

/*
 * Receive the parent b_value and eq_bits(u[0..k - 1], b[0..k - 1]) eval, as
 * well as the value of u_{n_stack - num_bits + 1}. Note that this forces
 * each num_bits to be in [0, n_stack], as lookups are only provided for this
 * range and idx = 0 lookups are all consumed by EqBaseAir.
 */
self.eq_rand_values_bus.lookup_key(
    builder,
    local.proof_idx,
    EqRandValuesLookupMessage {
        idx: AB::Expr::from_usize(self.n_stack + 1) - local.num_bits,
        u: local.u_val.map(Into::into),
    },
    and(not(local.is_first), local.is_valid),
);

self.eq_bits_internal_bus.receive(
    builder,
    local.proof_idx,
    EqBitsInternalMessage {
        b_value: local.sub_b_value.into(),
        num_bits: local.num_bits.into() - AB::Expr::ONE,
        eval: local.sub_eval.map(Into::into),
        child_lsb: local.b_lsb.into(),
    },
    and(not(local.is_first), local.is_valid),
);

let b_value = AB::Expr::TWO * local.sub_b_value + local.b_lsb;
builder.assert_bool(local.b_lsb);

/*
 * Compute eq_bits(u, b) and send it to the appropriate internal and external
 * buses. Field internal_child_flag is odd iff it has a child with lsb 0, and
 * is >= 2 iff it has a child with new bit 1. Because internal message field
 * num_bits must be strictly increasing, each (b_value, num_bits) pair must be
 * unique by induction.
 */
let eval = ext_field_multiply(
    local.sub_eval,
    ext_field_subtract_scalar::<AB::Expr>(
        ext_field_subtract::<AB::Expr>(
            ext_field_add_scalar::<AB::Expr>(
                ext_field_multiply_scalar(local.u_val, AB::Expr::TWO * local.b_lsb),
                AB::Expr::ONE,
            ),
            local.u_val,
        ),
        local.b_lsb,
    ),
);

    let three = AB::F::from_u8(3);
    builder
        .when(not(local.is_valid))
        .assert_zero(local.internal_child_flag);
    builder
        .when_ne(local.internal_child_flag, three)
        .when_ne(local.internal_child_flag, AB::Expr::TWO)
        .assert_bool(local.internal_child_flag);

    // Multiplicity is f(x) = 1/3 * x * (x - 2) * (2x - 5), which is such that
    // f(0), f(2) = 0 and f(1), f(3) = 1.
    self.eq_bits_internal_bus.send(
        builder,
        local.proof_idx,
        EqBitsInternalMessage {
            b_value: b_value.clone(),
            num_bits: local.num_bits.into(),
            eval: eval.clone(),
            child_lsb: AB::Expr::ZERO,
        },
        local.internal_child_flag
            * (local.internal_child_flag - AB::Expr::TWO)
            * (local.internal_child_flag * AB::Expr::TWO - AB::Expr::from_u8(5))
            * three.inverse(),
    );

    // Multiplicity is f(x) = -1/6 * x * (x - 1) * (2x - 7), which is such that
    // f(0), f(1) = 0 and f(2), f(3) = 1.
    self.eq_bits_internal_bus.send(
        builder,
        local.proof_idx,
        EqBitsInternalMessage {
            b_value: b_value.clone(),
            num_bits: local.num_bits.into(),
            eval: eval.clone(),
            child_lsb: AB::Expr::ONE,
        },
        local.internal_child_flag
            * (AB::Expr::ONE - local.internal_child_flag)
            * (local.internal_child_flag * AB::Expr::TWO - AB::Expr::from_u8(7))
            * AB::F::from_u8(6).inverse(),
    );

    self.eq_bits_lookup_bus.add_key_with_lookups(
        builder,
        local.proof_idx,
        EqBitsLookupMessage {
            b_value: b_value * AB::Expr::from_usize(1 << self.l_skip),
            num_bits: local.num_bits.into(),
            eval,
        },
        local.is_valid * local.external_mult,
    );
}

#[repr(C)]
#[derive(AlignedBorrow)]
pub struct StackingClaimsCols<F> {
    // Proof index columns for continuations
    pub proof_idx: F,
    /// Row has a real stacking claim (bus interactions fire).
    pub is_valid: F,
    /// Row is padding within a proof block (no bus interactions).
    pub is_padding: F,
    pub is_first: F,
    /// Last row of the proof block (valid + padding). Triggers proof_idx
    /// transition and the w_stack check.
    pub is_last: F,

    // Correspond to stacking_claim
    pub commit_idx: F,
    pub stacked_col_idx: F,

    // Sampled transcript values
    pub tidx: F,
    pub mu: [F; D_EF],
    pub mu_pow: [F; D_EF],

    // μ PoW witness and sample for proof-of-work check
    pub mu_pow_witness: F,
    pub mu_pow_sample: F,

    // Global column index (0-indexed, increments by 1 per row within a proof
    // block, covering both valid and padding rows).
    pub global_col_idx: F,

    // Stacking claim and batched coefficient computed in OpeningClaimsCols
    pub stacking_claim: [F; D_EF],
    pub claim_coefficient: [F; D_EF],

    // Sum of each stacking_claim * claim_coefficient
    pub final_s_eval: [F; D_EF],

    // RLC of stacking claims using mu
    pub whir_claim: [F; D_EF],
}

let is_last_valid = and(local.is_valid, next.is_padding + local.is_last);
// Valid row that continues to another valid row in the same proof block:
// excludes the terminal valid row (before padding or block end).
let is_continuing_valid = and(
    local.is_valid,
    AB::Expr::ONE - next.is_padding - local.is_last,
);

builder.assert_bool(local.is_valid);
builder.assert_bool(local.is_padding);
builder.assert_bool(local.is_last);
// Last row in a proof block is exactly the nested-loop boundary for proof_idx.
builder.when(is_in_block.clone()).assert_eq(
    local.is_last,
    NestedForLoopSubAir::<2>::local_is_last(
        is_in_block.clone(),
        next_is_in_block.clone(),
        next.is_first,
    ),
);
// Once padding starts within a proof block, it stays padding
builder
    .when(local.is_padding * not(local.is_last))
    .assert_one(next.is_padding);
builder.when_first_row().assert_zero(local.proof_idx);
builder.when(local.is_first).assert_one(local.is_valid);

/*
 * Constrain that commit_idx and stacked_col_idx increment correctly.
 */
builder.when(local.is_first).assert_zero(local.commit_idx);
builder
    .when(local.is_first)
    .assert_zero(local.stacked_col_idx);

let mut when_same_proof = builder.when(is_continuing_valid.clone());
let commit_delta = next.commit_idx - local.commit_idx;

when_same_proof.assert_bool(commit_delta.clone());
when_same_proof
    .when(commit_delta.clone())
    .assert_zero(next.stacked_col_idx);
when_same_proof
    .when(not::<AB::Expr>(commit_delta))
    .assert_one(next.stacked_col_idx - local.stacked_col_idx);

/*
 * Constrain global_col_idx: starts at 0, is forced by NestedForLoopSubAir
 * to increment by exactly 1 within each proof block, and ends at w_stack - 1.
 */
builder
    .when(local.is_first)
    .assert_zero(local.global_col_idx);
builder
    .when(local.is_last * is_in_block)
    .assert_eq(local.global_col_idx, AB::Expr::from_usize(self.w_stack - 1));

self.stacking_indices_bus.add_key_with_lookups(
    builder,
    local.proof_idx,
    StackingIndexMessage {
        commit_idx: local.commit_idx,
        col_idx: local.stacked_col_idx,
    },
    local.is_valid * AB::Expr::from_usize(self.stacking_index_mult),
);

/*
 * Compute the running sum of stacking_claim * claim_coefficient values and then
 * constrain the final result to be equal to s_{n_stack}(u_{n_stack}), which is
 * sent from SumcheckRoundsAir.
 */
self.claim_coefficients_bus.receive(
    builder,
    local.proof_idx,
    ClaimCoefficientsMessage {
        commit_idx: local.commit_idx,
        stacked_col_idx: local.stacked_col_idx,
        coefficient: local.claim_coefficient,
    },
    local.is_valid,
);

assert_array_eq(
    &mut builder.when(local.is_first),
    ext_field_multiply(local.stacking_claim, local.claim_coefficient),
    local.final_s_eval,
);

assert_array_eq(
    &mut builder.when(is_continuing_valid.clone()),
    ext_field_add(
        ext_field_multiply(next.stacking_claim, next.claim_coefficient),
        local.final_s_eval,
    ),
    next.final_s_eval,
);

self.sumcheck_claims_bus.receive(
    builder,
    local.proof_idx,
    SumcheckClaimsMessage {
        module_idx: AB::Expr::TWO,
        value: local.final_s_eval.map(Into::into),
    },
    is_last_valid.clone(),
);

/*
 * Constrain transcript operations and send the final tidx to the WHIR module.
 */
self.stacking_tidx_bus.receive(
    builder,
    local.proof_idx,
    StackingModuleTidxMessage {
        module_idx: AB::Expr::TWO,
        tidx: local.tidx.into(),
    },
    local.is_first,
);

builder
    .when(is_continuing_valid.clone())
    .assert_eq(local.tidx + AB::F::from_usize(D_EF), next.tidx);

let mu_pow_offset = pow_tidx_count(self.mu_pow_bits);

for i in 0..D_EF {
    // Observe stacking_claim at tidx + 0..D_EF
    self.transcript_bus.receive(
        builder,
        local.proof_idx,
        TranscriptBusMessage {
            tidx: AB::Expr::from_usize(i) + local.tidx,
            value: local.stacking_claim[i].into(),
            is_sample: AB::Expr::ZERO,
        },
        local.is_valid,
    );

    // Sample μ at tidx + D_EF + mu_pow_offset + i (after μ PoW observe/sample if any)
    self.transcript_bus.receive(
        builder,
        local.proof_idx,
        TranscriptBusMessage {
            tidx: AB::Expr::from_usize(i + D_EF + mu_pow_offset) + local.tidx,
            value: local.mu[i].into(),
            is_sample: AB::Expr::ONE,
        },
        is_last_valid.clone(),
    );
}

if self.mu_pow_bits > 0 {
    // μ PoW: observe mu_pow_witness at tidx + D_EF (on last valid row only)
    self.transcript_bus.receive(
        builder,
        local.proof_idx,
        TranscriptBusMessage {
            tidx: AB::Expr::from_usize(D_EF) + local.tidx,
            value: local.mu_pow_witness.into(),
            is_sample: AB::Expr::ZERO,
        },
        is_last_valid.clone(),
    );

    // μ PoW: sample mu_pow_sample at tidx + D_EF + 1 (on last valid row only)
    self.transcript_bus.receive(
        builder,
        local.proof_idx,
        TranscriptBusMessage {
            tidx: AB::Expr::from_usize(D_EF + 1) + local.tidx,
            value: local.mu_pow_sample.into(),
            is_sample: AB::Expr::ONE,
        },
        is_last_valid.clone(),
    );

    // μ PoW check: g^{mu_pow_sample[0:mu_pow_bits]} = 1
    self.exp_bits_len_bus.lookup_key(
        builder,
        ExpBitsLenMessage {
            base: AB::F::GENERATOR.into(),
            bit_src: local.mu_pow_sample.into(),
            num_bits: AB::Expr::from_usize(self.mu_pow_bits),
            result: AB::Expr::ONE,
        },
        is_last_valid.clone(),
    );
}

/*
 * Compute the RLC of the stacking claims and send it to the WHIR module.
 * Running sums propagate through valid rows only (not(is_last_valid)),
 * since padding rows have zero claims and don't affect the accumulators.
 */
assert_one_ext(&mut builder.when(local.is_first), local.mu_pow);
assert_array_eq(
    &mut builder.when(is_continuing_valid.clone()),
    local.mu,
    next.mu,
);
assert_array_eq(
    &mut builder.when(is_continuing_valid.clone()),
    ext_field_multiply(local.mu, local.mu_pow),
    next.mu_pow,
);

assert_array_eq(
    &mut builder.when(local.is_first),
    local.stacking_claim,
    local.whir_claim,
);

assert_array_eq(
    &mut builder.when(is_continuing_valid.clone()),
    ext_field_add(
        ext_field_multiply(next.stacking_claim, next.mu_pow),
        local.whir_claim,
    ),
    next.whir_claim,
);

// Send to WHIR module with tidx after all transcript operations
self.whir_module_bus.send(
    builder,
    local.proof_idx,
    WhirModuleMessage {
        tidx: AB::Expr::from_usize(2 * D_EF + mu_pow_offset) + local.tidx,
        claim: local.whir_claim.map(Into::into),
    },
    is_last_valid.clone(),
);
self.whir_mu_bus.send(
    builder,
    local.proof_idx,
    WhirMuMessage {
        mu: local.mu.map(Into::into),
    },
    is_last_valid,
);
